    zaehler_16            number(*, 5),
    zaehler_17            number(*, 5),
    zaehler_18            number(*, 5),
    zaehler_19            number(*, 5),
    zaehler_20            number(*, 5),
    zaehler_21            number(*, 5),
    zaehler_22            number(*, 5),
    zaehler_23            number(*, 5),
    zaehler_24            number(*, 5),
    zaehler_25            number(*, 5),
    delta_zaehler_0       number(*, 5),
    delta_zaehler_1       number(*, 5),
    delta_zaehler_2       number(*, 5),
    delta_zaehler_3       number(*, 5),
    delta_zaehler_4       number(*, 5),
    delta_zaehler_5       number(*, 5),
    delta_zaehler_6       number(*, 5),
    delta_zaehler_7       number(*, 5),
    delta_zaehler_8       number(*, 5),
    delta_zaehler_9       number(*, 5),
    delta_zaehler_10      number(*, 5),
    delta_zaehler_11      number(*, 5),
    delta_zaehler_12      number(*, 5),
    delta_zaehler_13      number(*, 5),
    delta_zaehler_14      number(*, 5),
