    delta_zaehler_22      number(*, 5),
    delta_zaehler_23      number(*, 5),
    delta_zaehler_24      number(*, 5),
    delta_zaehler_25      number(*, 5)
);

alter table dirkspzm32.mde_statistik
    add constraint pk_mde_statistik
        primary key ( sid,
                      firma_nr,
                      name,
                      datum )
            using index enable;


